const body    = $input.first().json.body ?? $input.first().json;
const data    = body.data    ?? body;
const key     = data.key     ?? body.key     ?? {};
const message = data.message ?? body.message ?? {};

if (key.fromMe === true) return [];
if ((key.remoteJid ?? '').includes('@g.us')) return [];

const from = (key.remoteJid ?? '')
  .replace('@s.whatsapp.net', '')
  .replace('@g.us', '');

if (!from || from.length < 5) return [];

const texto    = (message.conversation ?? message.extendedTextMessage?.text ?? message.buttonsResponseMessage?.selectedDisplayText ?? message.listResponseMessage?.singleSelectReply?.selectedRowId ?? '').trim();
const buttonId = message.buttonsResponseMessage?.selectedButtonId ?? message.listResponseMessage?.singleSelectReply?.selectedRowId ?? null;
const instance = body.instance ?? data.instance ?? 'bot-bruno';

return [{ json: { from, texto, buttonId, instance } }];

const p = $('Parsear Mensagem').item.json;
let responsaveis = [], sessoes = [];
try { const t = $('GET Responsavel').item.json.data ?? $('GET Responsavel').item.json; responsaveis = typeof t === 'string' ? JSON.parse(t) : (Array.isArray(t) ? t : []); } catch(e) { responsaveis = []; }
try { const t = $('GET Sessao').item.json.data ?? $('GET Sessao').item.json; sessoes = typeof t === 'string' ? JSON.parse(t) : (Array.isArray(t) ? t : []); } catch(e) { sessoes = []; }
const r = responsaveis[0] ?? null;
const s = sessoes[0] ?? null;
return [{ json: {
  from:                  p.from,
  texto:                 p.texto,
  buttonId:              p.buttonId,
  instance:              p.instance,
  responsavelEncontrado: r !== null,
  responsavelId:         r?.id    ?? null,
  responsavelNome:       r?.nome  ?? null,
  responsavelAluno:      r?.aluno ?? null,
  responsavelTurma:      r?.turma ?? null,
  sessaoEtapa:           s?.etapa ?? null,
  sessaoDados:           s?.dados ?? {}
} }];

const d = $json;
const etapa = d.sessaoEtapa, texto = d.texto ?? '', dados = d.sessaoDados ?? {};
let nd = { ...dados }, prox = null, resp = '', ok = false;

if (!etapa) {
  resp = 'Olá! Bem-vindo ao bot da escola. 😊\n\nDigite o seu *nome completo* como responsável:';
  prox = 'aguardando_nome'; nd = {};
} else if (etapa === 'aguardando_nome') {
  if (texto.length < 3) { resp = '⚠️ Nome muito curto. Digite seu nome completo.'; prox = 'aguardando_nome'; }
  else {
    nd.nome = texto;
    resp = `Obrigado, *${texto}*! 👋\n\nAgora me informe o *nome da criança* e qual *turma/ano* ela está:\n\n_(ex: João - 3A, Maria / 2° ano B)_`;
    prox = 'aguardando_aluno_turma';
  }
} else if (etapa === 'aguardando_aluno_turma') {
  if (texto.length < 2) { resp = '⚠️ Por favor, informe o nome da criança e a turma.'; prox = 'aguardando_aluno_turma'; }
  else {
    const sep = texto.includes(',') ? ',' : texto.includes(' - ') ? ' - ' : texto.includes('/') ? '/' : null;
    if (sep) {
      const parts = texto.split(sep).map(s => s.trim());
      nd.aluno = parts[0];
      nd.turma = parts.slice(1).join(' ').trim();
    } else {
      nd.aluno = texto; nd.turma = '';
    }
    ok = true;
    resp = `✅ *Cadastro realizado!*\n\n👤 ${nd.nome}\n👶 ${nd.aluno}${nd.turma ? ' — ' + nd.turma : ''}\n\nBem-vindo(a)! Envie qualquer mensagem para ver o menu. 🎉`;
  }
}

return [{ json: { from: d.from, instance: d.instance, resp, prox, nd: JSON.stringify(nd), ok, nome: nd.nome ?? '', aluno: nd.aluno ?? '', turma: nd.turma ?? '' } }];

const d = $json;
const t = (d.texto ?? '').trim();
const upper = t.toUpperCase();
const b = d.buttonId;
const etapa = d.sessaoEtapa ?? '';

let rota = 'menu';
if (upper === 'CANCELAR') rota = 'cancelar';
else if (etapa.startsWith('autorizacao_')) rota = 'autorizacao';
else if (etapa.startsWith('reserva_')) rota = 'reserva';
else if (etapa.startsWith('ocorrencia_')) rota = 'ocorrencia';
else if (etapa.startsWith('solicitacao_')) rota = 'solicitacao';
else if (b === 'btn_agenda' || t === '1') rota = 'agenda';
else if (b === 'btn_cardapio' || t === '2') rota = 'cardapio';
else if (b === 'btn_autorizacao' || t === '3') rota = 'autorizacao';
else if (b === 'btn_reserva' || t === '4') rota = 'reserva';
else if (b === 'btn_ocorrencia' || t === '5') rota = 'ocorrencia';
else if (b === 'btn_solicitacao' || t === '6') rota = 'solicitacao';
else if (b === 'btn_avisos' || t === '7') rota = 'avisos';

return [{ json: { ...d, rota } }];

const raw = $input.first().json.data ?? $input.first().json;
let lista = [];
try { lista = typeof raw === 'string' ? JSON.parse(raw) : (Array.isArray(raw) ? raw : []); } catch(e) { lista = []; }
const ctx = $('Roteador').item.json;
const from = ctx.from, instance = ctx.instance, turma = ctx.responsavelTurma;

// Filtrar eventos da turma do aluno + eventos gerais (turma null)
const filtrados = lista.filter(e => !e.turma || e.turma === turma);

if (filtrados.length === 0) {
  return [{ json: { from, instance, msg: '📅 *Agenda Escolar*\n\nNenhum evento programado nos próximos dias. 😊\n\nFique de olho! Assim que houver algo, avisamos por aqui.' } }];
}
let t = `📅 *Próximos Eventos*\n\n`;
filtrados.forEach(e => {
  const dt = e.data ? new Date(e.data + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'short', day: '2-digit', month: '2-digit' }) : '?';
  const turmaLabel = e.turma ? ` _(${e.turma})_` : ' _(Todos)_';
  t += `📌 *${e.titulo}*${turmaLabel}\n   📅 ${dt}\n`;
  if (e.descricao) t += `   ${e.descricao}\n`;
  t += '\n';
});
t += '_Para mais informações, fale com a coordenação._ 🏫';
return [{ json: { from, instance, msg: t } }];

const raw = $input.first().json.data ?? $input.first().json;
let lista = [];
try { lista = typeof raw === 'string' ? JSON.parse(raw) : (Array.isArray(raw) ? raw : []); } catch(e) { lista = []; }
const ctx = $('Roteador').item.json;
const from = ctx.from, instance = ctx.instance;

if (lista.length === 0) {
  return [{ json: { from, instance, msg: '🍽️ *Cardápio Semanal*\n\nO cardápio desta semana ainda não foi publicado.\n\nConsulte a coordenação para mais informações. 😊' } }];
}
const c = lista[0];
const semana = new Date(c.semana_inicio + 'T12:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
let msg = `🍽️ *Cardápio da Semana*\n_Semana de ${semana}_\n\n`;
if (c.segunda) msg += `🔵 *Segunda:* ${c.segunda}\n`;
if (c.terca)   msg += `🟢 *Terça:*   ${c.terca}\n`;
if (c.quarta)  msg += `🟡 *Quarta:*  ${c.quarta}\n`;
if (c.quinta)  msg += `🟠 *Quinta:*  ${c.quinta}\n`;
if (c.sexta)   msg += `🔴 *Sexta:*   ${c.sexta}\n`;
msg += '\n_Bom apetite! 😋🥗_';
return [{ json: { from, instance, msg } }];

const d = $json;
const etapa = d.sessaoEtapa, texto = d.texto ?? '', dados = d.sessaoDados ?? {};
let nd = { ...dados }, prox = null, resp = '', ok = false;

if (!etapa || etapa === 'autorizacao_nome') {
  if (!etapa) {
    resp = '✅ *Autorizar Busca do Aluno*\n\n_Quem você deseja autorizar a buscar ' + d.responsavelAluno + '?_\n\nDigite o *nome completo* do autorizador:';
    prox = 'autorizacao_nome';
  } else {
    if (texto.length < 3) { resp = '⚠️ Nome muito curto. Digite o nome completo.'; prox = 'autorizacao_nome'; }
    else { nd.nome = texto; resp = `📄 *Documento do autorizador*\n\nQual o número do RG ou CPF de *${texto}*?`; prox = 'autorizacao_documento'; }
  }
} else if (etapa === 'autorizacao_documento') {
  if (texto.length < 3) { resp = '⚠️ Documento inválido. Tente novamente.'; prox = 'autorizacao_documento'; }
  else { nd.documento = texto; resp = `👨‍👩‍👧 *Parentesco*\n\nQual o parentesco de *${nd.nome}* com ${d.responsavelAluno}?\n\n_(Ex: Avó, Tio, Vizinho, Babá)_`; prox = 'autorizacao_parentesco'; }
} else if (etapa === 'autorizacao_parentesco') {
  nd.parentesco = texto; ok = true;
  resp = `✅ *Autorização registrada!*\n\n👤 ${nd.nome}\n📄 Doc: ${nd.documento}\n👨‍👩‍👧 ${nd.parentesco}\n\nEsta pessoa está autorizada a buscar *${d.responsavelAluno}*. ✅\n\nA coordenação foi notificada.`;
}

return [{ json: { from: d.from, instance: d.instance, responsavelId: d.responsavelId, aluno: d.responsavelAluno, resp, prox, nd: JSON.stringify(nd), ok } }];

const d = $json;
const etapa = d.sessaoEtapa, texto = d.texto ?? '', dados = d.sessaoDados ?? {};
let nd = { ...dados }, prox = null, resp = '', ok = false;

if (!etapa || etapa === 'ocorrencia_titulo') {
  if (!etapa) {
    resp = '⚠️ *Registrar Ocorrência*\n\nQual o *assunto* da ocorrência?\n\n_(Ex: Queda no recreio, Conflito com colega, Problema de saúde)_';
    prox = 'ocorrencia_titulo';
  } else {
    if (texto.length < 3) { resp = '⚠️ Descrição muito curta. Tente novamente.'; prox = 'ocorrencia_titulo'; }
    else { nd.titulo = texto; resp = `📝 *Descreva o ocorrido*\n\nConte com mais detalhes o que aconteceu:`; prox = 'ocorrencia_descricao'; }
  }
} else if (etapa === 'ocorrencia_descricao') {
  if (texto.length < 5) { resp = '⚠️ Descrição muito curta. Informe mais detalhes.'; prox = 'ocorrencia_descricao'; }
  else { nd.descricao = texto; resp = `🚨 *Urgência*\n\nQual a urgência desta ocorrência?\n\n🟢 baixa\n🟡 media\n🔴 alta`; prox = 'ocorrencia_urgencia'; }
} else if (etapa === 'ocorrencia_urgencia') {
  const urg = texto.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  nd.urgencia = ['baixa','media','alta'].includes(urg) ? urg : 'media';
  ok = true;
  const proto = 'OC-' + String(Date.now()).slice(-6);
  nd.protocolo = proto;
  resp = `✅ *Ocorrência registrada!*\n\n📋 Assunto: ${nd.titulo}\n🚨 Urgência: ${nd.urgencia}\n🔖 Protocolo: *${proto}*\n\nA coordenação irá analisar e entrará em contato. 🏫`;
}

return [{ json: { from: d.from, instance: d.instance, responsavelId: d.responsavelId, aluno: d.responsavelAluno, resp, prox, nd: JSON.stringify(nd), ok } }];

const d = $json;
const etapa = d.sessaoEtapa, texto = d.texto ?? '', dados = d.sessaoDados ?? {};
let nd = { ...dados }, prox = null, resp = '', ok = false;

if (!etapa || etapa === 'solicitacao_tipo') {
  if (!etapa) {
    resp = '📋 *Solicitações Administrativas*\n\nQual o tipo de solicitação?\n\n🔹 Declaração de matrícula\n🔹 Histórico escolar\n🔹 Transferência\n🔹 Segundo via de contrato\n🔹 Outros\n\n_Digite o tipo ou descreva brevemente:_';
    prox = 'solicitacao_tipo';
  } else {
    if (texto.length < 3) { resp = '⚠️ Descreva o tipo de solicitação.'; prox = 'solicitacao_tipo'; }
    else { nd.tipo = texto; resp = `📝 *Detalhes da Solicitação*\n\nDescreva com mais detalhes o que precisa:`; prox = 'solicitacao_descricao'; }
  }
} else if (etapa === 'solicitacao_descricao') {
  if (texto.length < 5) { resp = '⚠️ Descreva melhor sua solicitação.'; prox = 'solicitacao_descricao'; }
  else {
    nd.descricao = texto; ok = true;
    const proto = 'SL-' + String(Date.now()).slice(-6);
    nd.protocolo = proto;
    resp = `✅ *Solicitação registrada!*\n\n📋 Tipo: ${nd.tipo}\n🔖 Protocolo: *${proto}*\n\nA secretaria analisará sua solicitação em até 2 dias úteis. 📅\n\n_Dúvidas? Ligue para a secretaria._`;
  }
}

return [{ json: { from: d.from, instance: d.instance, responsavelId: d.responsavelId, resp, prox, nd: JSON.stringify(nd), ok } }];

const raw = $input.first().json.data ?? $input.first().json;
let lista = [];
try { lista = typeof raw === 'string' ? JSON.parse(raw) : (Array.isArray(raw) ? raw : []); } catch(e) { lista = []; }
const ctx = $('Roteador').item.json;
const from = ctx.from, instance = ctx.instance, nome = ctx.responsavelNome;

if (lista.length === 0) {
  return [{ json: { from, instance, msg: '📢 *Meus Avisos*\n\nVocê não tem avisos pendentes no momento. ✅\n\n_Assim que a escola enviar algo, você receberá aqui!_' } }];
}
let t = `📢 *Seus Avisos* (${lista.length})\n\n`;
lista.forEach((a, i) => {
  const dt = a.created_at ? new Date(a.created_at).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric' }) : '?';
  t += `📌 *${a.titulo}*\n   ${a.mensagem}\n   _${dt}_\n\n`;
});
t += '_Para mais informações, entre em contato com a escola. 🏫_';
return [{ json: { from, instance, msg: t, ids: lista.map(a => a.id) } }];

const d = $json;
const etapa = d.sessaoEtapa, texto = d.texto ?? '', dados = d.sessaoDados ?? {};
let nd = { ...dados }, prox = null, resp = '', ok = false;

if (!etapa || etapa === 'reserva_local') {
  if (!etapa) {
    resp = '📅 *Fazer Reserva*\n\nQual espaço você deseja reservar?\n\n🔹 Sala de Reunião\n🔹 Auditório\n🔹 Sala de Atividades\n🔹 Quadra Esportiva\n\n_Digite o nome do espaço:_';
    prox = 'reserva_local';
  } else {
    if (texto.length < 3) { resp = '⚠️ Informe o nome do espaço desejado.'; prox = 'reserva_local'; }
    else { nd.local = texto; resp = `📆 *Data da Reserva*\n\nQual a data desejada para reservar *${texto}*?\n\n_Informe no formato DD/MM/AAAA:_`; prox = 'reserva_data'; }
  }
} else if (etapa === 'reserva_data') {
  const match = texto.match(/^(\d{2})/(\d{2})/(\d{4})$/);
  if (!match) { resp = '⚠️ Data inválida. Use o formato DD/MM/AAAA.'; prox = 'reserva_data'; }
  else {
    const [, dd, mm, yyyy] = match;
    const iso = `${yyyy}-${mm}-${dd}`;
    nd.data = iso; nd.dataFmt = texto;
    resp = `⏰ *Horário*\n\nQual o horário para a reserva de *${nd.local}* no dia *${texto}*?\n\n_(Ex: 09:00, 14:30)_`;
    prox = 'reserva_horario';
  }
} else if (etapa === 'reserva_horario') {
  nd.horario = texto; ok = true;
  const proto = 'RV-' + String(Date.now()).slice(-6);
  nd.protocolo = proto;
  resp = `✅ *Reserva registrada!*\n\n📆 Espaço: ${nd.local}\n📅 Data: ${nd.dataFmt}\n⏰ Horário: ${nd.horario}\n🔖 Protocolo: *${proto}*\n\nA coordenação irá confirmar sua reserva. 🏫\n\n_Status: Pendente de aprovação_`;
}

return [{ json: { from: d.from, instance: d.instance, responsavelId: d.responsavelId, resp, prox, nd: JSON.stringify(nd), ok } }];
